// C2: Acting Components
instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor for cart movement driven by a Trinamic TMC4671‑Eval motor controller"
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor for hoist movement driven by a Trinamic TMC4671‑Eval motor controller"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the hoist end for picking up pucks, powered by the PSU"
]

