instance CraneCADModel : DTDFVocab:Model [
    base:desc "Fusion‑360 CAD model of the lab‑scale gantry crane"
    DTDFVocab:inputTo GantryPythonLibEnabler
]

instance CraneKinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used by the Trajectory Generation Service to compute motion plans"
    DTDFVocab:inputTo GantryPythonLibEnabler
]

instance CraneSimulationModel : DTDFVocab:Model [
    base:desc "Digital replica of the crane and its controllers employed by the Simulation Service"
    DTDFVocab:inputTo GantryPythonLibEnabler
]

// C11: Enablers
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker for inter‑service messaging"
    DTDFVocab:enables DataLoggingService, TrajectoryGenerationService,
                SimulationService, ContinuousValidationService,
                HumanMachineInterfaceService
]

instance TimescaleDBEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB (PostgreSQL‑based) for persistent time‑series storage"
    DTDFVocab:enables DataLoggingService, DataVisualizationService
]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboards for visualising operational data"
    DTDFVocab:enables DataVisualizationService
]

instance DockerComposeEnabler : DTDFVocab:Enabler [
    base:desc "Docker‑Compose orchestrates containerised services on a single host"
    DTDFVocab:enables DataLoggingService, DataVisualizationService,
                TrajectoryGenerationService, SimulationService,
                ContinuousValidationService, HumanMachineInterfaceService
]

instance GantryPythonLibEnabler : DTDFVocab:Enabler [
    base:desc "Python 'gantrylib' package providing control logic and data handling"
    DTDFVocab:enables DataLoggingService, ContinuousValidationService,
                TrajectoryGenerationService, SimulationService
]

